import React, { useState, useEffect } from "react";
import api from "../api/api";
import {
  BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer,
  CartesianGrid, LineChart, Line, Cell
} from "recharts";

// ── Mock data generators (fallback when API not ready) ─────────────────────
const STATES = ["Kerala","Karnataka","Tamil Nadu","Telangana","Andhra Pradesh","Puducherry"];
const DISTRICTS = {
  "Kerala":   ["Ernakulam","Kozhikode","Thiruvananthapuram","Thrissur","Kottayam"],
  "Karnataka":["Bengaluru Urban","Mysuru","Mangaluru","Hubli-Dharwad","Belgaum"],
  "Tamil Nadu":["Chennai","Coimbatore","Madurai","Salem","Trichy"],
  "Telangana":["Hyderabad","Warangal","Karimnagar","Nizamabad","Khammam"],
  "Andhra Pradesh":["Visakhapatnam","Vijayawada","Guntur","Tirupati","Kakinada"],
  "Puducherry":["Puducherry","Karaikal","Mahe","Yanam"],
};

const mockRegionData = (products) => STATES.map(state => ({
  state,
  total_units: Math.floor(Math.random() * 1800) + 200,
  stores: Math.floor(Math.random() * 14) + 2,
  products: products.slice(0, Math.floor(Math.random() * products.length) + 1)
    .map(p => ({
      product_name: p.product_name,
      units: Math.floor(Math.random() * 600) + 50,
      risk: ["low","medium","high"][Math.floor(Math.random()*3)]
    }))
}));

const mockDistrictData = (state) => (DISTRICTS[state] || []).map(d => ({
  district: d,
  units: Math.floor(Math.random() * 500) + 40,
  stores: Math.floor(Math.random() * 5) + 1,
}));

const mockTrendData = () => {
  const base = [280,310,295,340,320,380,360,410,390,440,420,470,450,490,510,530];
  return Array.from({length:14}, (_,i) => ({
    date: `Feb ${i+4}`,
    units: base[i] + Math.floor(Math.random()*40 - 20)
  }));
};

const RISK_CFG = {
  high:   { color:"var(--danger)", bg:"#FEE2E2", label:"High Risk" },
  medium: { color:"var(--warn)",   bg:"#FEF3C7", label:"Medium" },
  low:    { color:"var(--ok)",     bg:"#DCFCE7", label:"Low Risk" },
};

const BAR_COLORS = ["#3A6FF7","#6B8EF9","#9DB3FB","#C5D2FD","#D6E0FE","#E8EDFF"];

const CustomBarTooltip = ({ active, payload, label }) => {
  if (!active || !payload?.length) return null;
  return (
    <div style={{background:"white",border:"1px solid var(--border)",borderRadius:10,padding:"10px 14px",fontSize:13}}>
      <div style={{color:"var(--muted)",marginBottom:4}}>{label}</div>
      <div style={{fontWeight:700,color:"var(--accent)"}}>{payload[0].value.toLocaleString()} units</div>
    </div>
  );
};

export default function AnalyticsPage() {
  const [products, setProducts] = useState([]);
  const [selectedProduct, setSelectedProduct] = useState(null);
  const [selectedState, setSelectedState] = useState(null);
  const [regionData, setRegionData] = useState([]);
  const [districtData, setDistrictData] = useState([]);
  const [trendData, setTrendData] = useState([]);
  const [stockoutData, setStockoutData] = useState([]);
  const [period, setPeriod] = useState("monthly");
  const [loading, setLoading] = useState(true);
  const [tab, setTab] = useState("overview"); // overview | regions | stockout

  useEffect(() => {
    const load = async () => {
      setLoading(true);
      try {
        const pRes = await api.get("/manufacturer/products");
        const prods = pRes.data?.products || [];
        setProducts(prods);

        // Try real analytics endpoints; fall back to mock
        try {
          const aRes = await api.get(`/manufacturer/analytics?period=${period}`);
          setRegionData(aRes.data?.regions || mockRegionData(prods));
          setTrendData(aRes.data?.trend   || mockTrendData());
          setStockoutData(aRes.data?.stockout || []);
        } catch (_) {
          setRegionData(mockRegionData(prods));
          setTrendData(mockTrendData());
          setStockoutData(prods.slice(0,5).map(p => ({
            product_name: p.product_name,
            at_risk_stores: Math.floor(Math.random()*8),
            total_stores: Math.floor(Math.random()*10)+8,
            risk_level: ["low","medium","high"][Math.floor(Math.random()*3)]
          })));
        }

        if (prods.length > 0) setSelectedProduct(prods[0]);
      } catch (_) {
        const fallback = [{product_name:"Maggi Noodles 280g",category:"Noodles"},{product_name:"Coca-Cola 600ml",category:"Beverages"}];
        setProducts(fallback);
        setSelectedProduct(fallback[0]);
        setRegionData(mockRegionData(fallback));
        setTrendData(mockTrendData());
      } finally {
        setLoading(false);
      }
    };
    load();
  }, [period]);

  useEffect(() => {
    if (selectedState) setDistrictData(mockDistrictData(selectedState));
  }, [selectedState]);

  const totalUnits = regionData.reduce((s,r) => s + (r.total_units||0), 0);
  const totalStores = regionData.reduce((s,r) => s + (r.stores||0), 0);
  const topState = [...regionData].sort((a,b)=>b.total_units-a.total_units)[0];

  if (loading) return (
    <div className="centered" style={{minHeight:"60vh"}}>
      <div className="spinner"/>
      <span style={{color:"var(--muted)",fontSize:14}}>Loading analytics…</span>
    </div>
  );

  if (products.length === 0) return (
    <>
      <div className="page-header">
        <div className="page-title">Analytics</div>
      </div>
      <div className="card">
        <div className="empty-state">
          <div className="empty-icon">📊</div>
          <div className="empty-title">No products listed</div>
          <div className="empty-sub">Go to My Products and add the products you manufacture to see analytics</div>
        </div>
      </div>
    </>
  );

  return (
    <>
      <div className="page-header" style={{display:"flex",alignItems:"flex-start",justifyContent:"space-between",flexWrap:"wrap",gap:12}}>
        <div>
          <div className="page-title">Analytics</div>
          <div className="page-sub">Aggregated insights from anonymous store data across the Reco network</div>
        </div>
        <div className="period-row">
          {[["Daily","daily"],["Weekly","weekly"],["Monthly","monthly"]].map(([l,v])=>(
            <button key={v} className={`period-chip${period===v?" active":""}`} onClick={()=>setPeriod(v)}>{l}</button>
          ))}
        </div>
      </div>

      {/* ── Product selector ── */}
      {products.length > 1 && (
        <div style={{display:"flex",gap:8,flexWrap:"wrap",marginBottom:20}}>
          {products.map((p,i)=>(
            <button key={i}
              onClick={()=>setSelectedProduct(p)}
              style={{
                padding:"7px 14px",borderRadius:20,border:"1.5px solid",
                fontFamily:"inherit",fontSize:12,fontWeight:600,cursor:"pointer",
                transition:"all 0.15s",
                borderColor: selectedProduct?.id===p.id ? "var(--accent)" : "var(--border)",
                background:  selectedProduct?.id===p.id ? "var(--accent-dim)" : "var(--surface)",
                color:       selectedProduct?.id===p.id ? "var(--accent)" : "var(--muted)",
              }}>
              {p.product_name.length > 30 ? p.product_name.slice(0,28)+"…" : p.product_name}
            </button>
          ))}
        </div>
      )}

      {/* ── KPI row ── */}
      <div className="grid-4" style={{marginBottom:24}}>
        {[
          { label:"Total units sold", value: totalUnits.toLocaleString(), sub:`${period} · all regions` },
          { label:"Active stores",    value: totalStores, sub:"Selling this product" },
          { label:"Top region",       value: topState?.state || "—", sub:`${topState?.total_units?.toLocaleString()||0} units`, isText:true },
          { label:"At-risk stores",   value: stockoutData.filter(s=>s.risk_level==="high").length, sub:"High stockout risk", danger:true },
        ].map((s,i)=>(
          <div className="card card-sm" key={i}>
            <div className="stat-label">{s.label}</div>
            <div className="stat-value" style={{
              fontSize: s.isText?18:28,
              color: s.danger&&s.value>0?"var(--danger)":"var(--text)"
            }}>{s.value}</div>
            <div className="stat-sub">{s.sub}</div>
          </div>
        ))}
      </div>

      {/* ── Tabs ── */}
      <div style={{marginBottom:20}}>
        <div className="tab-row" style={{maxWidth:360}}>
          {[["overview","Overview"],["regions","By Region"],["stockout","Stockout Risk"]].map(([v,l])=>(
            <button key={v} className={`tab${tab===v?" active":""}`} onClick={()=>setTab(v)}>{l}</button>
          ))}
        </div>
      </div>

      {/* ── Tab: Overview ── */}
      {tab === "overview" && (
        <div className="grid-2">
          {/* Trend */}
          <div className="card">
            <div className="section-head">
              <div>
                <div className="section-title">Sales Trend</div>
                <div className="section-sub">{selectedProduct?.product_name?.slice(0,32)}</div>
              </div>
            </div>
            <ResponsiveContainer width="100%" height={200}>
              <LineChart data={trendData} margin={{left:-20,right:4,top:4,bottom:0}}>
                <CartesianGrid stroke="var(--border)" vertical={false}/>
                <XAxis dataKey="date" tick={{fontSize:10,fill:"var(--muted)"}} axisLine={false} tickLine={false} interval={2}/>
                <YAxis tick={{fontSize:10,fill:"var(--muted)"}} axisLine={false} tickLine={false}/>
                <Tooltip content={<CustomBarTooltip/>}/>
                <Line type="monotone" dataKey="units" stroke="var(--accent)" strokeWidth={2.5} dot={false} activeDot={{r:4}}/>
              </LineChart>
            </ResponsiveContainer>
          </div>

          {/* Region bar */}
          <div className="card">
            <div className="section-head">
              <div className="section-title">Units by State</div>
              <div className="section-sub">Click a bar to drill down</div>
            </div>
            <ResponsiveContainer width="100%" height={200}>
              <BarChart data={regionData} margin={{left:-20,right:4,top:4,bottom:0}}
                onClick={d=>d?.activePayload && setSelectedState(d.activePayload[0]?.payload?.state)}>
                <CartesianGrid stroke="var(--border)" vertical={false}/>
                <XAxis dataKey="state" tick={{fontSize:9,fill:"var(--muted)"}} axisLine={false} tickLine={false}/>
                <YAxis tick={{fontSize:10,fill:"var(--muted)"}} axisLine={false} tickLine={false}/>
                <Tooltip content={<CustomBarTooltip/>}/>
                <Bar dataKey="total_units" radius={[6,6,0,0]} cursor="pointer">
                  {regionData.map((_,i)=>(
                    <Cell key={i} fill={BAR_COLORS[i % BAR_COLORS.length]}/>
                  ))}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>
      )}

      {/* ── Tab: By Region ── */}
      {tab === "regions" && (
        <div className="grid-2">
          {/* State list */}
          <div className="card">
            <div className="section-head">
              <div className="section-title">State Performance</div>
              <div className="section-sub">Click to see district breakdown</div>
            </div>
            {regionData.sort((a,b)=>b.total_units-a.total_units).map((r,i)=>(
              <div key={i} onClick={()=>setSelectedState(r.state)}
                style={{
                  display:"flex",alignItems:"center",gap:12,padding:"12px",
                  borderRadius:10,cursor:"pointer",marginBottom:4,
                  background: selectedState===r.state ? "var(--accent-dim)" : "transparent",
                  transition:"background 0.12s"
                }}
                onMouseEnter={e=>{ if(selectedState!==r.state) e.currentTarget.style.background="var(--bg)"; }}
                onMouseLeave={e=>{ if(selectedState!==r.state) e.currentTarget.style.background="transparent"; }}
              >
                <div style={{width:28,height:28,borderRadius:8,background:BAR_COLORS[i%BAR_COLORS.length]+"22",
                  display:"grid",placeItems:"center",fontSize:12,fontWeight:700,color:BAR_COLORS[i%BAR_COLORS.length]}}>
                  {i+1}
                </div>
                <div style={{flex:1}}>
                  <div style={{fontWeight:600,fontSize:13,color: selectedState===r.state?"var(--accent)":"var(--text)"}}>{r.state}</div>
                  <div style={{fontSize:11,color:"var(--muted)"}}>{r.stores} stores · {r.total_units?.toLocaleString()} units</div>
                </div>
                <div style={{width:80}}>
                  <div className="progress-bar">
                    <div className="progress-fill" style={{
                      width:`${Math.round((r.total_units/Math.max(...regionData.map(x=>x.total_units)))*100)}%`,
                      background:BAR_COLORS[i%BAR_COLORS.length]
                    }}/>
                  </div>
                </div>
              </div>
            ))}
          </div>

          {/* District drill-down */}
          <div className="card">
            {selectedState ? (
              <>
                <div className="section-head">
                  <div>
                    <div className="section-title">{selectedState}</div>
                    <div className="section-sub">District-level breakdown</div>
                  </div>
                  <button className="btn btn-outline btn-sm" onClick={()=>setSelectedState(null)}>Clear</button>
                </div>
                <ResponsiveContainer width="100%" height={180}>
                  <BarChart data={districtData} layout="vertical" margin={{left:0,right:20,top:0,bottom:0}}>
                    <CartesianGrid stroke="var(--border)" horizontal={false}/>
                    <XAxis type="number" tick={{fontSize:10,fill:"var(--muted)"}} axisLine={false} tickLine={false}/>
                    <YAxis type="category" dataKey="district" tick={{fontSize:11,fill:"var(--text)"}} axisLine={false} tickLine={false} width={110}/>
                    <Tooltip content={<CustomBarTooltip/>}/>
                    <Bar dataKey="units" radius={[0,6,6,0]} fill="var(--accent)"/>
                  </BarChart>
                </ResponsiveContainer>
                <div style={{marginTop:16}}>
                  {districtData.sort((a,b)=>b.units-a.units).slice(0,3).map((d,i)=>(
                    <div key={i} className="region-card" style={{borderLeftColor:BAR_COLORS[i]}}>
                      <div style={{fontWeight:600,fontSize:13}}>{d.district}</div>
                      <div style={{fontSize:11,color:"var(--muted)",marginTop:2}}>{d.units} units · {d.stores} store{d.stores!==1?"s":""}</div>
                    </div>
                  ))}
                </div>
              </>
            ) : (
              <div className="empty-state">
                <div className="empty-icon">🗺️</div>
                <div className="empty-title">Select a state</div>
                <div className="empty-sub">Click any state on the left to see district-level data</div>
              </div>
            )}
          </div>
        </div>
      )}

      {/* ── Tab: Stockout Risk ── */}
      {tab === "stockout" && (
        <div className="card">
          <div className="section-head">
            <div>
              <div className="section-title">Stockout Risk Overview</div>
              <div className="section-sub">Based on 7-day demand forecast · anonymous store data</div>
            </div>
          </div>
          {stockoutData.length === 0 ? (
            <div className="empty-state">
              <div className="empty-icon">✅</div>
              <div className="empty-title">No stockout data available</div>
              <div className="empty-sub">Risk data will appear as stores sync their inventory</div>
            </div>
          ) : (
            <div className="table-wrap">
              <table>
                <thead>
                  <tr>
                    <th>Product</th>
                    <th>At-risk stores</th>
                    <th>Total stores</th>
                    <th>Coverage</th>
                    <th>Risk level</th>
                  </tr>
                </thead>
                <tbody>
                  {stockoutData.map((s,i)=>{
                    const cfg = RISK_CFG[s.risk_level] || RISK_CFG.low;
                    const pct = s.total_stores > 0 ? Math.round((s.at_risk_stores/s.total_stores)*100) : 0;
                    return (
                      <tr key={i}>
                        <td style={{fontWeight:500}}>{s.product_name}</td>
                        <td style={{fontWeight:700,color:s.at_risk_stores>3?"var(--danger)":"var(--text)"}}>{s.at_risk_stores}</td>
                        <td>{s.total_stores}</td>
                        <td style={{width:160}}>
                          <div style={{display:"flex",alignItems:"center",gap:8}}>
                            <div className="progress-bar" style={{flex:1}}>
                              <div className="progress-fill" style={{width:`${pct}%`,background:cfg.color}}/>
                            </div>
                            <span style={{fontSize:12,color:"var(--muted)",width:32}}>{pct}%</span>
                          </div>
                        </td>
                        <td>
                          <span className="chip" style={{background:cfg.bg,color:cfg.color}}>
                            <div className="risk-dot" style={{background:cfg.color}}/>
                            {cfg.label}
                          </span>
                        </td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
          )}
        </div>
      )}
    </>
  );
}
